const fs = require('fs');
let token = '';
try {
  token = fs.readFileSync('/var/run/secrets/kubernetes.io/serviceaccount/token', 'utf8').trim();
} catch (e) {
  return [{ json: { pg_logs: 'No K8s token: ' + e.message } }];
}
const headers = { 'Authorization': 'Bearer ' + token };
let pgLogs = '';
try {
  const jobsResp = await fetch('https://kubernetes.default.svc/apis/batch/v1/namespaces/databases/jobs?labelSelector=app%3Dpg-backup', { headers });
  const jobsData = await jobsResp.json();
  const jobs = (jobsData.items || []).sort((a, b) => new Date(b.metadata.creationTimestamp) - new Date(a.metadata.creationTimestamp)).slice(0, 1);
  for (const job of jobs) {
    const podsResp = await fetch('https://kubernetes.default.svc/api/v1/namespaces/databases/pods?labelSelector=job-name%3D' + job.metadata.name, { headers });
    const podsData = await podsResp.json();
    const pod = (podsData.items || [])[0];
    if (pod) {
      const logResp = await fetch('https://kubernetes.default.svc/api/v1/namespaces/databases/pods/' + pod.metadata.name + '/log', { headers });
      pgLogs = await logResp.text();
    }
  }
} catch (e) {
  pgLogs = 'Error fetching PG backup logs: ' + e.message;
}
return [{ json: { pg_logs: pgLogs || 'No pg-backup job found' } }];

