const fs = require('fs');
const prev = $input.first().json;

// Only fetch on Sundays (getDay() === 0)
const isSunday = new Date().getDay() === 0;
if (!isSunday) {
  return [{ json: { ...prev, restore_verify_logs: '', is_sunday: false } }];
}

let token = '';
try {
  token = fs.readFileSync('/var/run/secrets/kubernetes.io/serviceaccount/token', 'utf8').trim();
} catch (e) {
  return [{ json: { ...prev, restore_verify_logs: 'No K8s token: ' + e.message, is_sunday: true } }];
}

const headers = { 'Authorization': 'Bearer ' + token };
let restoreLogs = '';

try {
  // Most recent restore-verify job (runs Sundays 6am — this fetches last week's completed result)
  const jobsResp = await fetch(
    'https://kubernetes.default.svc/apis/batch/v1/namespaces/databases/jobs?labelSelector=app%3Drestore-verify',
    { headers }
  );
  const jobsData = await jobsResp.json();
  const jobs = (jobsData.items || [])
    .sort((a, b) => new Date(b.metadata.creationTimestamp) - new Date(a.metadata.creationTimestamp))
    .slice(0, 1);

  for (const job of jobs) {
    const podsResp = await fetch(
      'https://kubernetes.default.svc/api/v1/namespaces/databases/pods?labelSelector=job-name%3D' + job.metadata.name,
      { headers }
    );
    const podsData = await podsResp.json();
    const pod = (podsData.items || [])[0];
    if (pod) {
      const logResp = await fetch(
        'https://kubernetes.default.svc/api/v1/namespaces/databases/pods/' + pod.metadata.name + '/log',
        { headers }
      );
      restoreLogs = await logResp.text();
    }
    const jobStatus = job.status.succeeded ? 'SUCCEEDED' : job.status.failed ? 'FAILED' : 'UNKNOWN';
    restoreLogs = '[Job: ' + job.metadata.name + ' — ' + jobStatus + ']\n' + restoreLogs;
  }
} catch (e) {
  restoreLogs = 'Error fetching restore-verify logs: ' + e.message;
}

return [{ json: { ...prev, restore_verify_logs: restoreLogs || 'No restore-verify job found', is_sunday: true } }];

